/**
 * @name BourneShell working directory injection - taint flow
 * @description Trace working directory from Commandline.setWorkingDirectory through to shell command construction
 * @kind path-problem
 * @problem.severity error
 * @id java/plexus-workdir-taint-flow
 * @tags security
 *       external/cwe/cwe-078
 */
import java
import semmle.code.java.dataflow.TaintTracking

module WorkDirInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Working directory set via setWorkingDirectory or setWorkingDirectoryAsString
    exists(MethodCall mc |
      (mc.getMethod().hasName("setWorkingDirectory") or
       mc.getMethod().hasName("setWorkingDirectoryAsString")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.codehaus.plexus.util.cli.shell", "Shell") and
      source.asExpr() = mc.getArgument(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink is the append call in getExecutionPreamble that builds cd command
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getEnclosingCallable().hasName("getExecutionPreamble") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module WorkDirFlow = TaintTracking::Global<WorkDirInjectionConfig>;
import WorkDirFlow::PathGraph

from WorkDirFlow::PathNode source, WorkDirFlow::PathNode sink
where WorkDirFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Working directory value flows unescaped into shell preamble (cd command) from $@.", source.getNode(), "setWorkingDirectory call"

/**
 * @name Commandline setExecutable flows to Runtime.exec without shell metachar escaping
 * @description Executable name set on Commandline flows via shell quoting to Runtime.exec 
 * @kind path-problem
 * @problem.severity error
 * @id java/plexus-executable-to-exec
 * @tags security
 *       external/cwe/cwe-078
 *       external/cwe/cwe-088
 */
import java
import semmle.code.java.dataflow.TaintTracking

module ExecTaintConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Executable is set via setExecutable on Commandline or Shell
    exists(MethodCall mc |
      mc.getMethod().hasName("setExecutable") and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("org.codehaus.plexus.util.cli.shell", "Shell") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.codehaus.plexus.util.cli.shell", "Shell")
      ) and
      source.asExpr() = mc.getArgument(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Sink: Runtime.exec() call
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ExecTaintFlow = TaintTracking::Global<ExecTaintConfig>;
import ExecTaintFlow::PathGraph

from ExecTaintFlow::PathNode source, ExecTaintFlow::PathNode sink
where ExecTaintFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Executable value flows to Runtime.exec from $@.", source.getNode(), "setExecutable call"
